INSERT INTO `memory_entry`
(`title`, `summary`, `content`, `memory_date`, `cover_image_url`, `cover_storage_path`, `mood_tags`, `is_featured`, `visibility`, `sort_order`, `favorite_count`)
VALUES
('灯下把线稿递给你的夜晚','她把平板里的线稿举起来，像认真分享一个还没完成的小世界，连台灯都变得很温柔。','那天晚上书桌很满，画稿、纸张、平板和台灯都挤在一起，却一点也不显得乱。\n\n她坐在桌前，把平板里的线稿举到镜头前，好像是在说：你看，这里有我刚刚画下来的东西。那一刻不是正式展示作品，更像是把正在发生的生活悄悄递出来一点。她的表情很平静，可那份认真藏在眼睛里，很容易被记住。\n\n我喜欢这种还没完成的时刻。因为它不是结果，而是过程里的小亮光。以后再翻到这一页，会想起她在灯下慢慢画画，也会想起那些普通夜晚里，认真生活本身就已经很可爱。','2026-06-22','/uploads/photos/187_小可_书桌前展示平板线稿照.png','photos/187_小可_书桌前展示平板线稿照.png','书桌,画稿,夜晚',1,'PUBLIC',300,NULL),
('斑马线上的夜色刚刚好','她穿着制服裙站在夜晚的斑马线上，路灯把她照得很清楚，像青春刚好从那里经过。','夜晚的街道有一点热闹，路灯、车灯和斑马线把画面切成了很清楚的几格。\n\n她站在斑马线上，制服裙和领结都被光照住，整个人看起来安静又明亮。那不是摆拍到很夸张的漂亮，而是刚好走到这里，刚好停下来，刚好被夜色温柔地接住。后来侧身走过的那一张也很好，像故事不是停在原地，而是继续往前翻了一页。\n\n我把这组放进手账，是因为它很像一个可以被记住的路口。那天也许只是普通出门，可照片留下来的时候，普通的夜晚就多了一点故事感。','2026-06-22','/uploads/photos/194_小可_夜晚斑马线制服行走照.png','photos/194_小可_夜晚斑马线制服行走照.png','夜晚,斑马线,制服',1,'PUBLIC',310,NULL),
('湖边白裙吹过来的风','她坐在湖边石头上，白裙和黑外套被风轻轻托着，像夏天忽然安静下来的一秒。','湖边那天的光很亮，水面也很亮，连风都像带着一点透明感。\n\n她坐在石头上，白裙铺开一点，黑外套搭在外面，整个人被湖边的颜色衬得很清爽。背后是水和树，远处有城市的线条，可画面最安静的地方还是她坐着的那一小块石头。她没有特别用力地看镜头，只是待在那里，就把那阵风也留住了。\n\n这种照片很适合以后慢慢翻。因为它不是一眼就很热闹的记忆，而是越看越觉得舒服。像某个夏天真的来过，也真的在她身边停了一会儿。','2026-06-23','/uploads/photos/197_小可_湖边白裙黑外套坐姿照.png','photos/197_小可_湖边白裙黑外套坐姿照.png','湖边,白裙,夏天',1,'PUBLIC',320,NULL),
('把制服裙穿得很乖的一天','紫色领结和格裙被她整理得整整齐齐，站在房间里时，像一页干净又可爱的校园手账。','房间里的光不算特别亮，但很适合记录她安静站着的样子。\n\n紫色领结、格裙、白衬衫，每一处都显得很乖。她站在镜头前，没有太多动作，却把那种清清爽爽的可爱留得很完整。黑领结和黑裙那一张也很干净，像同一天里另一种更安静的版本。\n\n我喜欢把这些照片放在一起看。它们没有复杂的情节，却很像小可日常里稳定出现的那种气质：认真、干净、柔软，还有一点只有熟悉以后才会发现的小可爱。','2026-06-23','/uploads/photos/200_小可_室内紫色领结格裙全身照.png','photos/200_小可_室内紫色领结格裙全身照.png','制服,格裙,可爱',0,'PUBLIC',330,NULL);
